INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('cdf713ade2868d2a', 'KS', '["federal"]', 'election_dates', 'Is there a U.S. Senate race in Kansas in 2026?', '["When is Roger Marshall up for re-election?","Is Jerry Moran on the ballot in 2026?","U.S. Senate election cycle Kansas 2026"]', 'Yes. Incumbent Senator Roger Marshall (R, Class 2) is up for re-election in 2026. Senator Jerry Moran (Class 3) was re-elected in 2022 and is not on the ballot again until 2028.', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State - Elections', '2026-05-14', 'per_cycle', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('c5c9e9401103f574', 'KS', '["state"]', 'candidate_eligibility', 'Is Governor Laura Kelly running for re-election in 2026?', '["Can Laura Kelly seek a third term?","Is the Kansas Governor''s seat open in 2026?","Kansas gubernatorial term limits"]', 'No. Governor Laura Kelly (D) is term-limited and cannot seek a third consecutive term under Article 1, Section 1 of the Kansas Constitution. The 2026 gubernatorial election is an open-seat race.', 'https://kslib.info/1376/Governor-Term-Limits', 'Kansas Constitution Article 1, Section 1', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('0e4122c065bac8b1', 'KS', '["state"]', 'ballot_access', 'Do candidates for Governor and Lieutenant Governor run on a joint ticket in Kansas?', '["How is the Lieutenant Governor selected in KS?","Joint ticket requirements for KS Governor","Do I vote for Governor and Lt. Gov separately in the primary?"]', 'Yes. Under K.S.A. 25-4001, candidates for Governor and Lieutenant Governor run as a joint ticket in both the primary and general elections. They are elected by a single vote cast for the pair.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_040_0001.html', 'K.S.A. 25-4001', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('79bb7ed05fcd178c', 'KS', '["state"]', 'election_dates', 'Which statewide executive offices are on the 2026 Kansas ballot?', '["Is the Attorney General up for election in 2026?","Kansas statewide elections 2026 list","When is the next Secretary of State election in KS?"]', 'The following statewide executive offices are up for election in 2026: Governor/Lieutenant Governor, Secretary of State, Attorney General, State Treasurer, and Commissioner of Insurance. All serve four-year terms.', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State - Election Calendar', '2026-05-14', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('a63ff0ca21afb05d', 'KS', '["state"]', 'election_dates', 'Are any Kansas State Senate seats up for election in 2026?', '["Kansas Senate election cycle","When is the next KS State Senate election?","Are all 40 Kansas Senate seats up in 2026?"]', 'No. The 40 members of the Kansas Senate serve four-year terms and were last elected in 2024. They are next up for election in 2028. Unlike many states, Kansas Senate terms are not staggered; all seats are elected concurrently in presidential years per K.S.A. 25-101.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_001_0001.html', 'K.S.A. 25-101', '2026-05-14', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('362ed86bd0534ebc', 'KS', '["state"]', 'election_dates', 'How many Kansas House of Representatives seats are up for election in 2026?', '["Kansas House term lengths","Is my State Rep on the ballot in 2026?","KS House election cycle"]', 'All 125 seats in the Kansas House of Representatives are up for election in 2026. Members serve two-year terms and are elected in every even-numbered year.', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'State Legislative candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('f1cb9dc55b07fcea', 'KS', '["federal","state","county","judicial"]', 'election_dates', 'When is the 2026 primary election in Kansas?', '["Kansas primary date 2026","When do polls open for the KS primary?","August 2026 Kansas election"]', 'The Kansas primary election is held on Tuesday, August 4, 2026. Under K.S.A. 25-203, the primary is held on the first Tuesday of August in even-numbered years.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_002_0003.html', 'K.S.A. 25-203', '2026-05-14', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('311899682d6038b3', 'KS', '["federal","state","county"]', 'filing_requirements', 'What is the filing deadline for major party candidates in Kansas for 2026?', '["When to file for office in KS 2026","Kansas candidate filing deadline","June 1st deadline Kansas"]', 'The filing deadline for major party candidates to appear on the 2026 primary ballot is June 1, 2026, at 12:00 noon. If June 1 falls on a weekend, the deadline is the following Monday per K.S.A. 25-205.', 'https://www.sos.ks.gov/elections/candidate-filing.html', 'Kansas Secretary of State - Candidate Filing', '2026-05-14', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('ce04072e58234fb7', 'KS', '["federal","state","county"]', 'filing_requirements', 'What is the filing deadline for independent candidates in Kansas for 2026?', '["Kansas independent candidate petition deadline","August 3rd deadline Kansas","How late can an independent file in KS?"]', 'Independent candidates must file their petitions or declarations by 12:00 noon on the Monday preceding the primary election. For 2026, this deadline is August 3, 2026, per K.S.A. 25-305.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_003_0005.html', 'K.S.A. 25-305', '2026-05-14', 'per_cycle', 'statute_citation', 'Independent candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('a2902553de469a02', 'KS', '["judicial"]', 'election_dates', 'What is the historic August 2026 judicial selection ballot measure in Kansas?', '["Kansas Supreme Court selection change 2026","August 2026 ballot measure judges","Direct election of judges Kansas amendment"]', 'In August 2026, Kansas voters will decide a constitutional amendment to change the selection process for Supreme Court Justices. The measure proposes moving from the unique ''Supreme Court Nominating Commission'' merit system to a model where the Governor appoints justices subject to Senate confirmation, similar to the federal system.', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State - Proposed Amendments', '2026-05-14', 'volatile', 'official_source_direct', 'Judicial candidates and legal consultants', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('c6c1b967e12602bb', 'KS', '["judicial"]', 'election_dates', 'How are Kansas Supreme Court Justices currently selected?', '["Kansas Supreme Court Nominating Commission","KS merit selection for judges","Who picks the Supreme Court in Kansas?"]', 'Currently, Kansas uses a merit selection system where a nonpartisan Supreme Court Nominating Commission (composed of lawyers and non-lawyers) submits a list of three qualified candidates to the Governor. The Governor must appoint one candidate from that list; the Senate has no confirmation role under the current Article 3, Section 5.', 'https://www.kscourts.org/Judges/Supreme-Court/Supreme-Court-Nominating-Commission', 'Kansas Judicial Branch', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('7f6250884de960c0', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Is a photo ID required to vote in person in Kansas?', '["Kansas voter ID requirements","Do I need my license to vote in KS?","Safe voting photo ID Kansas"]', 'Yes. K.S.A. 25-2908 requires any person desiring to vote in person to provide a valid form of photo identification. Acceptable forms include a driver''s license, U.S. passport, or government employee ID. Specific exemptions exist for certain religious objections or voters over age 65 using expired IDs.', 'https://www.sos.ks.gov/elections/photo-id.html', 'K.S.A. 25-2908', '2026-05-14', 'static', 'statute_citation', 'All voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('7222bfa55c67646d', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the voter registration deadline in Kansas?', '["Last day to register to vote in KS","Kansas voter registration cutoff","Does Kansas have same-day registration?"]', 'The deadline to register to vote is 21 days before any election per K.S.A. 25-2311. Kansas does NOT have same-day voter registration for new voters; applications must be submitted by the 21-day cutoff.', 'https://www.sos.ks.gov/elections/voter-registration.html', 'K.S.A. 25-2311', '2026-05-14', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('2de0a21bb7bc1e9c', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Kansas allow no-excuse advance (early) voting?', '["Can I vote early in Kansas?","Kansas advance voting by mail rules","How to request an absentee ballot in KS"]', 'Yes. Under K.S.A. 25-1119, any registered voter may vote ''advance'' in person or by mail without providing an excuse. In-person advance voting typically begins 20 days before the election, though the start date varies by county.', 'https://www.sos.ks.gov/elections/voter-information.html', 'K.S.A. 25-1119', '2026-05-14', 'static', 'statute_citation', 'All voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('33fb6c5a4ce0a529', 'KS', '["state","county","municipal","judicial"]', 'finance_ethics', 'Who regulates campaign finance in Kansas?', '["Where do I file campaign ethics reports in KS?","Kansas Governmental Ethics Commission role","Who enforces contribution limits in Kansas?"]', 'Campaign finance and ethics laws in Kansas are administered and enforced by the Kansas Governmental Ethics Commission (GEC). They oversee reporting for state and local candidates and investigate violations of the Campaign Finance Act.', 'https://ethics.kansas.gov/', 'Kansas Governmental Ethics Commission', '2026-05-14', 'static', 'official_source_direct', 'All state and local candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('c7c84f22b07301cf', 'KS', '["state","county","municipal"]', 'finance_ethics', 'What are the contribution limits for statewide candidates in Kansas?', '["How much can I donate to a Governor candidate in KS?","Kansas statewide campaign donation caps","Contribution limits for AG in Kansas"]', 'For statewide offices (Governor/Lt. Gov, SoS, AG, Treasurer, Insurance), the limit is $2,000 per donor per election (primary and general are separate). This applies to individuals, PACs, and corporations.', 'https://ethics.kansas.gov/campaign-finance/contribution-limits/', 'K.S.A. 25-4153', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('1d6ba5a3e7475c4d', 'KS', '["state","county","municipal"]', 'recall_rules', 'Can state officials be recalled in Kansas?', '["How to recall a Kansas legislator","Can Governor Kelly be recalled?","Kansas recall petition requirements"]', 'Yes. Unlike many states, Kansas allows the recall of all elected state and local officials, except judicial officers, under Article 4, Section 3 of the Kansas Constitution. Recalls must be based on specific grounds such as misconduct in office, incompetence, or failure to perform duties.', 'https://kslib.info/1310/Recall-of-Elected-Officials', 'Kansas Constitution Article 4, Section 3', '2026-05-14', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('99698ad5c1f5993a', 'KS', '["county"]', 'election_dates', 'How many counties are in Kansas and who runs their elections?', '["Does every county in KS have its own election officer?","Kansas county-level election administration","Who manages voting in Johnson County KS?"]', 'Kansas has 105 counties. Elections are administered by the County Election Officer. In the four largest counties (Johnson, Sedgwick, Shawnee, and Wyandotte), this is a dedicated Election Commissioner appointed by the Secretary of State; in others, it is the elected County Clerk.', 'https://www.sos.ks.gov/elections/county-election-officers.html', 'Kansas Secretary of State - County Officials', '2026-05-14', 'static', 'official_source_direct', 'Candidates and Local Officials', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('429a8403ec356669', 'KS', '["state"]', 'voter_interaction', 'What is the current legal status of abortion rights in Kansas?', '["Kansas 2022 Value Them Both vote","Hodes & Nauser abortion ruling","Is abortion legal in Kansas 2026?"]', 'Abortion is legal in Kansas. In 2019, the Kansas Supreme Court ruled in Hodes & Nauser that the state constitution protects a fundamental right to bodily autonomy, including abortion. In August 2022, voters overwhelmingly rejected the ''Value Them Both'' amendment, which would have removed that protection.', 'https://www.kscourts.org/KSCourts/media/KS-Courts/Opinions/114153.pdf', 'Hodes & Nauser v. Schmidt (2019)', '2026-05-14', 'volatile', 'statute_citation', 'All Campaigns and Strategists', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('1d41de668118d663', 'KS', '["federal","state"]', 'redistricting', 'Who draws the district maps in Kansas?', '["Does Kansas have an independent redistricting commission?","Redistricting authority Kansas","Who drew the 2022 KS congressional map?"]', 'The Kansas Legislature is responsible for drawing U.S. House and state legislative maps. Kansas does not have an independent redistricting commission. Maps are passed via bill and subject to a gubernatorial veto, though the legislature can override a veto with a two-thirds majority.', 'https://www.kslegresearch.org/KLRD-web/Redistricting.html', 'Kansas Legislative Research Department', '2026-05-14', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('5d84ff3c61dda3d7', 'KS', '["federal"]', 'redistricting', 'How many U.S. House districts does Kansas have for 2026?', '["Kansas congressional apportionment","How many congressmen does KS send to DC?","KS congressional districts 2026"]', 'Kansas is apportioned 4 U.S. House districts. All four districts will be on the 2026 ballot.', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('5cfbe62f162caf85', 'KS', '["state"]', 'candidate_eligibility', 'How are vacancies in the Kansas State Legislature filled?', '["Legislative vacancy process KS","Special election for KS State Senate","Who appoints a State Rep in Kansas?"]', 'Vacancies are filled by a precinct committeeperson caucus of the same political party that held the seat. The caucus elects a replacement, and the Governor then formally appoints that individual. There are no special elections for state legislative vacancies in Kansas per K.S.A. 25-3902.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_039_0002.html', 'K.S.A. 25-3902', '2026-05-14', 'static', 'statute_citation', 'Political Parties and Candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('a3ca39f69b4c79e8', 'KS', '["state","county","municipal"]', 'ballot_access', 'Does Kansas have a direct citizen initiative process?', '["Can citizens put laws on the ballot in KS?","Kansas ballot initiative rules","Citizen-led amendments Kansas"]', 'No. Kansas does not have a direct statewide initiative or referendum process for citizens to place statutes or constitutional amendments on the ballot. All ballot measures must be referred by the state legislature.', 'https://www.sos.ks.gov/elections/proposed-amendments.html', 'Kansas Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('06f3037cc06be145', 'KS', '["state"]', 'election_dates', 'Is the Secretary of State or Insurance Commissioner an appointed role in Kansas?', '["Who picks the KS Insurance Commissioner?","Electing the Secretary of State in KS","Statewide offices appointment vs election"]', 'No. Both the Secretary of State and the Commissioner of Insurance are elective offices in Kansas. They are elected to four-year terms concurrently with the Governor.', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('2f3e2bd6c3e16360', 'KS', '["state","county","municipal"]', 'finance_ethics', 'What are the individual contribution limits for state campaigns in Kansas?', '["How much can an individual give to a candidate in KS?","Kansas individual donation limits","Are there campaign contribution caps for individuals in Kansas?"]', 'Unlike states with unlimited contributions, Kansas caps donations per election cycle. For statewide offices, the limit is $2,000 per donor per election. For State Senate it is $1,000, and for State House or local offices, the limit is $500 per donor per election.', 'https://ethics.kansas.gov/campaign-finance/contribution-limits/', 'Kansas Governmental Ethics Commission', '2026-05-14', 'static', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('09fcd5368eac499d', 'KS', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for Governor of Kansas?', '["How old do you have to be to be KS Governor?","Gubernatorial candidate residency rules Kansas","Article 1 Section 3 Governor qualifications"]', 'Unlike most states, the Kansas Constitution does not specify an age requirement for the Governor. However, following a 2017 cycle where several teenagers ran, the legislature passed K.S.A. 25-4001a, which statutorily requires candidates for Governor and Lieutenant Governor to be at least 25 years old and qualified electors of the state.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_040_0001a.html', 'K.S.A. 25-4001a', '2026-05-14', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('0456759afa38171c', 'KS', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Kansas?', '["How old do you have to be to be KS Lt Governor?","Lieutenant Governor residency requirement Kansas","Qualifications for Lt Gov KS"]', 'Under K.S.A. 25-4001a, the qualifications for Lieutenant Governor are identical to those for the Governor: the candidate must be at least 25 years of age and a qualified elector (registered voter) of the state of Kansas.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_040_0001a.html', 'K.S.A. 25-4001a', '2026-05-14', 'static', 'statute_citation', 'Lieutenant Gubernatorial candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('e033ae37e5cec044', 'KS', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Kansas State Legislature?', '["How old to run for State Senate KS?","District residency for KS House candidates","Qualifications for Kansas State Representative"]', 'Under Article 2, Section 4 of the Kansas Constitution, the only age requirement for a State Senator or State Representative is that they must be a ''qualified elector'' (at least 18 years old). They must also reside in the district they seek to represent during their entire time as a candidate and while in office.', 'https://kslib.info/1373/Legislative-Qualifications', 'Kansas Constitution Article 2, Section 4', '2026-05-14', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('147e44d5668474a1', 'KS', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for U.S. Senate in Kansas?', '["How old do you have to be to run for Senate?","Congressional age limit Kansas","US Senate qualifications KS"]', 'Under the U.S. Constitution, a candidate for the U.S. Senate must be at least 30 years old, a U.S. citizen for nine years, and an inhabitant of Kansas when elected.', 'https://www.sos.ks.gov/elections/candidate-filing.html', 'Kansas Secretary of State / U.S. Constitution Art. I § 3', '2026-05-14', 'static', 'official_source_direct', 'U.S. Senate candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('8be7babb4ab1019e', 'KS', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for U.S. House in Kansas?', '["Do I have to live in the district to run for Congress in KS?","Congressional age limit Kansas","US House qualifications KS"]', 'Under the U.S. Constitution, a candidate for the U.S. House of Representatives must be at least 25 years old, a U.S. citizen for seven years, and an inhabitant of Kansas when elected. District residency is not a constitutional requirement.', 'https://www.sos.ks.gov/elections/candidate-filing.html', 'Kansas Secretary of State / U.S. Constitution Art. I § 2', '2026-05-14', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('714e0021224327ad', 'KS', '["state"]', 'candidate_eligibility', 'Does the Kansas Attorney General have to be a licensed attorney?', '["Do I have to be a lawyer to be AG in KS?","Attorney General qualifications Kansas","Kansas Bar requirement for Attorney General"]', 'Yes. While the Kansas Constitution does not explicitly list qualifications for the office, state law (K.S.A. 75-701) mandates that no person shall be eligible for the office of Attorney General unless they are a licensed attorney who is actively registered and in good standing with the Kansas Supreme Court.', 'http://www.ksrevisor.org/statutes/chapters/ch75/075_007_0001.html', 'K.S.A. 75-701', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('9b25452761a2f908', 'KS', '["county"]', 'candidate_eligibility', 'What are the specific qualifications to run for County Sheriff in Kansas?', '["Does a sheriff need a law enforcement background in KS?","Kansas Sheriff requirements","Can anyone run for Sheriff in Kansas?"]', 'Under K.S.A. 19-801b, candidates for County Sheriff must meet strict law enforcement qualifications. A candidate must possess a current, valid law enforcement officer certification from the Kansas Law Enforcement Training Center (or an equivalent out-of-state cert), and have no felony convictions or serious domestic violence convictions.', 'http://www.ksrevisor.org/statutes/chapters/ch19/019_008_0001b.html', 'K.S.A. 19-801b', '2026-05-14', 'static', 'statute_citation', 'County-level candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('76fea1aa3bb1708e', 'KS', '["state"]', 'election_dates', 'What is the structure of the Kansas State Board of Education?', '["Is the KS Board of Education partisan?","How many members on the Kansas State Board of Education?","KS BOE term length and elections"]', 'The Kansas State Board of Education consists of 10 members who are elected in partisan elections. They serve four-year staggered terms, with half of the board elected every two years during general election cycles.', 'https://www.ksde.org/Board', 'Kansas State Department of Education', '2026-05-14', 'static', 'official_source_direct', 'Statewide candidates and consultants', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('31e4aa75f325446d', 'KS', '["state"]', 'candidate_eligibility', 'What are the term limits for the Governor of Kansas?', '["How many times can the Kansas Governor be re-elected?","Kansas Governor term limit rules","Article 1 Section 1 consecutive terms"]', 'Under Article 1, Section 1 of the Kansas Constitution, the Governor is limited to serving two successive four-year terms. After serving two consecutive terms, a former governor must wait at least one full term (four years) before they are eligible to seek the office again.', 'https://kslib.info/1376/Governor-Term-Limits', 'Kansas Constitution Article 1, Section 1', '2026-05-14', 'static', 'statute_citation', 'Gubernatorial candidates and Strategists', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('73dd482c2e1d5a3e', 'KS', '["state"]', 'election_dates', 'What are the term lengths for Kansas State Senators and State Representatives?', '["How long is a KS House term?","KS State Senate term length","Legislative election cycle Kansas"]', 'Kansas State Representatives serve two-year terms, meaning the entire 125-member House is on the ballot every even-numbered year. Kansas State Senators serve four-year terms, and all 40 seats are elected concurrently during presidential election years (e.g., 2024, 2028).', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'State Legislative candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('d859ac09df5f24fa', 'KS', '["judicial"]', 'election_dates', 'What are the term lengths for justices and judges in Kansas?', '["How long do Supreme Court justices serve in KS?","Kansas Court of Appeals term limit","District court judge term length Kansas"]', 'Kansas Supreme Court Justices serve 6-year terms following their initial appointment and first retention election. Judges on the Kansas Court of Appeals and District Court judges both serve 4-year terms.', 'https://www.kscourts.org/Judges', 'Kansas Judicial Branch', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('5c55c5e680cd2c01', 'KS', '["municipal","special_district"]', 'election_dates', 'Are local school board elections in Kansas partisan or nonpartisan?', '["School board trustee elections KS","Do school board candidates run with a party label in Kansas?","Education board election schedule"]', 'Local school board elections in Kansas are strictly nonpartisan. Under K.S.A. 25-2021, members are elected to four-year terms. General elections for school boards are held in November of odd-numbered years.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_020_0021.html', 'K.S.A. 25-2021', '2026-05-14', 'static', 'statute_citation', 'School Board candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('fbd00700f9916f4c', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the deadline to request a mail-in advance ballot in Kansas?', '["When is the last day to ask for a mail ballot in KS?","Advance ballot application deadline Kansas","How many days before the election must I request an absentee ballot?"]', 'Under K.S.A. 25-1122, a voter''s application for a mail-in advance ballot must be received by the county election office no later than the Tuesday preceding the election (7 days prior).', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_011_0022.html', 'K.S.A. 25-1122', '2026-05-14', 'static', 'statute_citation', 'Absentee voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('d9cd3dc2149e11df', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the deadline for a mail-in advance ballot to be received in Kansas?', '["When is my absentee ballot due in KS?","Kansas mail ballot postmark rule","Election Day 7pm ballot receipt"]', 'Following a recent legislative override, Kansas no longer provides a 3-day postmark grace period. To be counted, an advance ballot must be physically received by the county election office or delivered to a polling place by 7:00 p.m. on Election Day.', 'https://www.sos.ks.gov/elections/voter-information.html', 'Kansas Secretary of State - Advance Voting', '2026-05-14', 'static', 'official_source_direct', 'Absentee voters and Campaigns', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('ca602369b81e1135', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What are the voting hours on Election Day in Kansas?', '["When do polls open and close in KS?","Kansas election day voting hours","What time do polls close on Election Day?"]', 'By default, Kansas polls are open from 7:00 a.m. to 7:00 p.m. on Election Day. However, K.S.A. 25-106 permits individual counties to open polls as early as 6:00 a.m. and close as late as 8:00 p.m.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_001_0006.html', 'K.S.A. 25-106', '2026-05-14', 'static', 'statute_citation', 'All voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('7291908dde034df5', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does a concealed carry license count as valid photo ID to vote in Kansas?', '["Valid ID list Kansas voting","Can I use a passport to vote in KS?","What counts as photo ID in Kansas?"]', 'Yes. Under K.S.A. 25-2908, a concealed carry of handgun license issued by Kansas or another state is explicitly accepted as a valid form of photographic identification for voting, alongside driver''s licenses, passports, and military IDs.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_029_0008.html', 'K.S.A. 25-2908', '2026-05-14', 'static', 'statute_citation', 'All voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('12ac06c9234e625d', 'KS', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in Kansas?', '["Felon voting rights KS","Voting post-incarceration rules Kansas","Can I vote while on probation in KS?"]', 'Yes, but only after full completion of their sentence. Under K.S.A. 21-6613, voting rights in Kansas are restored upon the final discharge of the felony sentence, which includes the completion of any term of probation, parole, or supervised release.', 'http://www.ksrevisor.org/statutes/chapters/ch21/021_066_0013.html', 'K.S.A. 21-6613', '2026-05-14', 'static', 'statute_citation', 'All eligible citizens', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('4bbc24ae818c1b4e', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Kansas still require proof of citizenship to register to vote under the SAFE Act?', '["Kansas SAVE database citizenship checks","Kobach proof of citizenship law status","Do I need a birth certificate to register to vote in KS?"]', 'No. The documentary proof of citizenship requirement introduced under the Kansas SAFE Act was struck down as unconstitutional by federal courts in the case Fish v. Kobach (2018). Voters are not required to provide a birth certificate or passport to register.', 'https://www.sos.ks.gov/elections/voter-registration.html', 'Kansas Secretary of State - Voter Registration', '2026-05-14', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('06a6a28ce4ccd36c', 'KS', '["federal","state"]', 'ballot_access', 'What is the petition signature threshold for an independent statewide candidate in Kansas?', '["How many signatures to run as an independent in KS?","Independent ballot access Governor Kansas","5,000 signature rule Kansas"]', 'Under Kansas law, an independent candidate running for a statewide office (such as Governor or U.S. Senate) must collect valid signatures from at least 5,000 registered voters to qualify for the general election ballot.', 'https://www.sos.ks.gov/elections/candidate-filing.html', 'Kansas Secretary of State - Candidate Filing', '2026-05-14', 'static', 'official_source_direct', 'Independent candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('d1c9f20df0d69bda', 'KS', '["federal","state","county","municipal"]', 'candidate_eligibility', 'Does Kansas have a sore loser law for independent candidates?', '["Can I run as an independent if I lose the primary in KS?","Kansas sore loser statute","Running for office after a primary defeat"]', 'Yes. Under K.S.A. 25-202(c), a candidate who is defeated in a partisan primary election is legally prohibited from running for the same office as an independent candidate in the subsequent general election.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_002_0002.html', 'K.S.A. 25-202(c)', '2026-05-14', 'static', 'statute_citation', 'Independent candidates and Strategists', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('d52e9a9e0c5ab35c', 'KS', '["federal","state","county"]', 'voter_interaction', 'Are Kansas primaries closed to unaffiliated voters?', '["Can independents vote in the KS Republican primary?","Kansas semi-closed primary system","Do I have to be registered with a party to vote in August?"]', 'Kansas utilizes a semi-closed primary system. While registered party members must vote in their own party''s primary, registered ''unaffiliated'' voters may declare a party affiliation at the polling place on Election Day to participate in that party''s primary.', 'https://www.sos.ks.gov/elections/voter-information.html', 'Kansas Secretary of State - Voter Information', '2026-05-14', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('c7f128e9f18922f1', 'KS', '["state","county","municipal"]', 'finance_ethics', 'Can corporations contribute directly to candidates in Kansas?', '["Are corporate contributions legal in KS?","Can my business donate to a state candidate?","Corporate campaign donation limits Kansas"]', 'Yes. Corporate treasury contributions to candidates are permitted in Kansas. However, corporations are subject to the exact same contribution limits as individuals (e.g., $2,000 for statewide, $1,000 for State Senate, $500 for State House).', 'https://ethics.kansas.gov/campaign-finance/contribution-limits/', 'Kansas Governmental Ethics Commission', '2026-05-14', 'static', 'official_source_direct', 'Corporations and Campaign Treasurers', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('9dd8709e011063cd', 'KS', '["state","county","municipal"]', 'recall_rules', 'What is the signature threshold to recall an elected official in Kansas?', '["How many signatures to recall a Kansas legislator?","Kansas recall petition requirements","40 percent recall threshold Kansas"]', 'Under K.S.A. 25-4325, a recall petition for a state officer requires valid signatures equal to at least 40% of the votes cast for all candidates for that office in the most recent general election.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_043_0025.html', 'K.S.A. 25-4325', '2026-05-14', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('a3525aed348a521d', 'KS', '["federal","state"]', 'redistricting', 'Did the 2022 Kansas redistricting maps survive court challenges?', '["Kansas redistricting litigation","Were the 2022 maps struck down in KS?","Gerrymandering lawsuits Kansas"]', 'Yes. The Kansas Supreme Court upheld the Republican-drawn congressional and state legislative maps, ruling that the Kansas Constitution does not explicitly prohibit partisan gerrymandering. The maps are fully operative for the 2026 cycle.', 'https://www.kslegresearch.org/KLRD-web/Redistricting.html', 'Kansas Legislative Research Department', '2026-05-14', 'static', 'official_source_direct', 'All federal and state candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('68929008d970b5b7', 'KS', '["state"]', 'candidate_eligibility', 'What are the qualifications for Kansas State Treasurer?', '["Requirements to run for KS State Treasurer","Who is eligible for Kansas Treasurer?","Treasurer candidate rules Kansas"]', 'To be eligible for State Treasurer, a candidate must be a qualified elector of Kansas (at least 18 years old and a registered voter). Unlike the Governor or Attorney General, there are no additional statutory age or professional requirements for this office under K.S.A. 25-101a.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_001_0001a.html', 'K.S.A. 25-101a', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('a5cf3a1161644245', 'KS', '["state"]', 'candidate_eligibility', 'What are the unique qualifications for Kansas Insurance Commissioner?', '["Do I need insurance experience to be KS Insurance Commissioner?","Insurance Commissioner candidate requirements KS","K.S.A. 40-109 qualifications"]', 'Yes. Under K.S.A. 40-109, the Commissioner of Insurance must be a person ''well versed and experienced'' in the business of insurance and must also be a qualified elector of Kansas. There are no specific degree requirements, but the experience mandate is a statutory prerequisite.', 'http://www.ksrevisor.org/statutes/chapters/ch40/040_001_0009.html', 'K.S.A. 40-109', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('eb88a74f9f45ab2b', 'KS', '["county"]', 'candidate_eligibility', 'Must a Kansas County Attorney be a licensed lawyer?', '["Qualifications for County Attorney in KS","Can a non-lawyer run for County Attorney in Kansas?","KS Bar requirement for local prosecutors"]', 'Yes. Per K.S.A. 19-701, a candidate for County Attorney must be a person who is ''regularly admitted to practice law in the state of Kansas'' and is in good standing with the Kansas Supreme Court at the time of election.', 'http://www.ksrevisor.org/statutes/chapters/ch19/019_007_0001.html', 'K.S.A. 19-701', '2026-05-14', 'static', 'statute_citation', 'County-level candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('919fdc95f14c9871', 'KS', '["state"]', 'candidate_eligibility', 'Is the Kansas Board of Regents an elected or appointed body?', '["Who picks the Board of Regents in KS?","Can I run for the KS Board of Regents?","Kansas higher education governance"]', 'The Kansas Board of Regents is an appointed body, not an elected one. Its nine members are appointed by the Governor and confirmed by the Kansas Senate to serve staggered four-year terms per K.S.A. 74-3202a.', 'https://www.kansasregents.org/about/regents-members', 'K.S.A. 74-3202a', '2026-05-14', 'static', 'official_source_direct', 'Statewide consultants and educators', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('9bb1eb34e868420d', 'KS', '["state","county"]', 'election_dates', 'What happens if the Governor of Kansas resigns or is unable to serve?', '["Gubernatorial vacancy process Kansas","Who succeeds the Governor in KS?","Does Kansas hold special elections for Governor?"]', 'Under Article 1, Section 11 of the Kansas Constitution, the Lieutenant Governor succeeds to the office of Governor if the office becomes vacant. There is no special election; the Lieutenant Governor serves the remainder of the four-year term.', 'https://kslib.info/1376/Governor-Term-Limits', 'Kansas Constitution Article 1, Section 11', '2026-05-14', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('83d3716cc29ef8cd', 'KS', '["judicial"]', 'election_dates', 'When are Kansas Supreme Court Justices subject to retention elections?', '["KS Supreme Court retention schedule","When do voters decide on keeping a justice in KS?","Retention election frequency Kansas"]', 'Justices are first subject to a retention election at the first general election held more than one year after their initial appointment. If retained, they then serve six-year terms and must face subsequent retention elections every six years.', 'https://www.kscourts.org/Judges/Supreme-Court/Retention', 'Kansas Judicial Branch', '2026-05-14', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('d084adbcfae67439', 'KS', '["judicial"]', 'election_dates', 'Why do some Kansas counties have partisan judicial elections while others use retention?', '["KS District Court election types","Merit selection vs partisan election for KS judges","Nonpartisan judicial districts Kansas"]', 'Kansas allows each judicial district to choose between partisan elections or merit selection (retention). In partisan districts, judges run with party labels for 4-year terms. In merit districts, judges are appointed and then face retention votes every 4 years per K.S.A. 20-2901.', 'https://www.kscourts.org/Judges/District-Courts', 'K.S.A. 20-2901', '2026-05-14', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('25ac2c38b108bb3e', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Are ballot drop boxes permitted in Kansas?', '["Can I use a drop box for my KS ballot?","Kansas drop box legality","Are drop boxes secure in Kansas?"]', 'Yes, drop boxes are currently permitted in Kansas. However, K.S.A. 25-1132 regulates their use, requiring them to be monitored, locked, and under the control of the county election officer. Individual counties determine the number and location of boxes.', 'https://www.sos.ks.gov/elections/voter-information.html', 'K.S.A. 25-1132', '2026-05-14', 'volatile', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('a2254b1863ca298b', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can I change my party affiliation on the day of the primary election in Kansas?', '["Primary day party switching KS","KS semi-closed primary party declaration","Changing affiliation at the polls in Kansas"]', 'Only if you are currently ''unaffiliated.'' Under K.S.A. 25-3304, voters already registered with a party (Republican, Democratic, etc.) must change their affiliation by the registration deadline. Unaffiliated voters, however, may declare a party affiliation at the polling place on primary day.', 'https://sos.ks.gov/elections/voter-information.html', 'K.S.A. 25-3304', '2026-05-14', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('e69d0987fdc657bd', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Kansas?', '["How close can I campaign to a KS polling place?","KS poll worker rules for campaigners","Buffer zone for voting in Kansas"]', 'In Kansas, electioneering is prohibited within 250 feet of the entrance to a polling place per K.S.A. 25-2430. This includes wearing campaign apparel or distributing materials within the restricted zone.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_024_030.html', 'K.S.A. 25-2430', '2026-05-14', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('64017c9a9cb9ce0f', 'KS', '["federal","state","county"]', 'ballot_access', 'How much does it cost to file for office in Kansas?', '["Filing fees for KS candidates 2026","Cost to run for KS Governor","Filing fee vs petition Kansas"]', 'Filing fees are typically 1% of the salary of the office sought. For example, for Governor, candidates pay 1% of the annual salary plus a small GEC reporting fee. Candidates may alternatively file by petition if they do not wish to pay the fee.', 'https://www.sos.ks.gov/elections/candidate-filing.html', 'Kansas Secretary of State', '2026-05-14', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('eff9a1663eb0778d', 'KS', '["federal","state"]', 'ballot_access', 'Which political parties are currently recognized in Kansas?', '["Minor parties in Kansas 2026","Is the Libertarian party on the KS ballot?","Kansas recognized party list"]', 'As of 2026, the recognized political parties in Kansas include the Republican, Democratic, and Libertarian parties. Recent shifts in the minor party landscape, such as the merger between No Labels Kansas and United Kansas (April 2026), have impacted the recognized list. Parties maintain status by ensuring a candidate for Governor receives at least 5% of the total vote.', 'https://sos.ks.gov/elections/voter-registration.html', 'Kansas Secretary of State', '2026-05-14', 'volatile', 'official_source_direct', 'Political parties and candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('1741b24eb499fade', 'KS', '["state","county","municipal"]', 'finance_ethics', 'What is the registration threshold for a candidate committee in Kansas?', '["When do I have to file with the KS GEC?","Kansas campaign committee registration limit","At what point is a campaign committee required in KS?"]', 'Candidates must file an Appointment of Treasurer form before they receive any contributions or make any expenditures. However, they are not required to file detailed disclosure reports until they meet the $1,000 threshold in receipts or expenditures per K.S.A. 25-4148.', 'https://ethics.kansas.gov/campaign-finance/candidate-treasurer-information/', 'K.S.A. 25-4148', '2026-05-14', 'static', 'statute_citation', 'Candidates and Treasurers', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('443b3827ebed7c46', 'KS', '["state","county","municipal"]', 'finance_ethics', 'What are the campaign finance reporting dates for Kansas in 2026?', '["KS campaign report deadlines 2026","When are GEC reports due in Kansas?","Kansas 2026 ethics reporting calendar"]', 'For the 2026 cycle, standard reports are due: January 10 (Annual Report), July 27 (Pre-Primary), and October 26 (Pre-General). Late filings result in a $100 per day penalty until filed per K.S.A. 25-4148.', 'https://ethics.kansas.gov/', 'Kansas Governmental Ethics Commission', '2026-05-14', 'per_cycle', 'official_source_direct', 'Candidates and PACs', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('119f1940227d3907', 'KS', '["state","county","municipal"]', 'finance_ethics', 'Does Kansas prohibit the personal use of campaign funds?', '["Can I use campaign money for personal items in KS?","KS personal use ban","Kansas ethics laws campaign spending"]', 'Yes. K.S.A. 25-4157a strictly prohibits the use of campaign funds for any personal purpose. Funds may only be used for legitimate campaign or holding-office expenses, such as travel, staffing, and advertising.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_041_057a.html', 'K.S.A. 25-4157a', '2026-05-14', 'static', 'statute_citation', 'Candidates and Treasurers', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('08f86eae567640fd', 'KS', '["state","county"]', 'recall_rules', 'How much time do proponents have to circulate a recall petition in Kansas?', '["KS recall petition deadline","Time limit for gathering recall signatures Kansas","Recall circulation period Kansas"]', 'Under K.S.A. 25-4324, once the application for a recall is certified, the committee has exactly 90 days to circulate and file the petition with the required number of signatures (40% of the last vote cast for the office).', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_043_024.html', 'K.S.A. 25-4324', '2026-05-14', 'static', 'statute_citation', 'Campaigns and Voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('3d68d8fe0e1bae69', 'KS', '["federal"]', 'recall_rules', 'Can U.S. Senators or Representatives be recalled in Kansas?', '["Recalling a KS Congressman","Is Roger Marshall subject to recall?","Federal recall rules in Kansas"]', 'No. While the Kansas Constitution allows the recall of state and local officials, Kansas AG Opinion 1994-35 clarifies that members of the U.S. Congress are not subject to state-level recall laws, as their qualifications and removal are governed solely by the U.S. Constitution.', 'https://ag.ks.gov/opinions', 'Kansas AG Opinion 1994-35', '2026-05-14', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('2ffe166fb425501c', 'KS', '["county"]', 'election_dates', 'Are County Commissioner elections in Kansas partisan or nonpartisan?', '["Kansas county commissioner election rules","Do KS commissioners run with a party?","County board election structure Kansas"]', 'County Commissioner elections in Kansas are partisan. Candidates run as Republicans, Democrats, or other recognized party members. Most counties have three commissioners serving staggered 4-year terms, though larger counties like Johnson have more.', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'County-level candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('a9f5eecb3d3fdade', 'KS', '["state"]', 'redistricting', 'Can the Governor of Kansas veto redistricting maps?', '["KS redistricting veto power","Redistricting override Kansas legislature","Who approves maps in Kansas?"]', 'Yes. Redistricting maps are passed as standard bills and are subject to a gubernatorial veto. However, the legislature can override a veto with a two-thirds majority in both chambers, which has occurred in recent cycles.', 'https://www.kslegresearch.org/KLRD-web/Redistricting.html', 'Kansas Legislative Research Department', '2026-05-14', 'static', 'official_source_direct', 'Statewide and legislative candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('1588f756fa488781', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Kansas offer online voter registration?', '["Can I register to vote online in KS?","Kansas electronic voter registration","KS SOS online registration"]', 'Yes. Kansas provides online voter registration for individuals with a valid Kansas driver''s license or non-driver ID card. Applicants without these forms of ID must use a paper application.', 'https://www.kdor.ks.gov/apps/voterreg/default.aspx', 'Kansas Department of Revenue / SOS', '2026-05-14', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('8726a66f074ef9b7', 'KS', '["municipal"]', 'candidate_eligibility', 'What are the qualifications to run for a Unified School District (USD) board in Kansas?', '["Requirements for KS school board candidates","USD board eligibility Kansas","Who can run for education board in KS?"]', 'A candidate for a USD board must be a registered voter and reside within the school district or the specific board member district they are seeking to represent. These elections are nonpartisan per K.S.A. 25-2021.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_020_0021.html', 'K.S.A. 25-2021', '2026-05-14', 'static', 'statute_citation', 'School board candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('24cf23fc82504c46', 'KS', '["municipal"]', 'candidate_eligibility', 'Does Kansas have township government?', '["Kansas township elections","KS township officer qualifications","What are Kansas townships?"]', 'Yes. Most Kansas counties are divided into townships, each governed by a three-member board (Trustee, Clerk, and Treasurer). Township officers are elected to four-year terms in partisan elections during even-numbered years.', 'https://www.sos.ks.gov/elections/elections.html', 'Kansas Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'Township candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('b3fb9ee8f4e8e809', 'KS', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How does a Kansas voter cast a provisional ballot?', '["Kansas provisional voting rules","When is a ballot counted as provisional in KS?","Curing a provisional ballot Kansas"]', 'A voter is given a provisional ballot if their eligibility is in question (e.g., name not on rolls, lack of ID). To have the ballot counted, the voter must usually ''cure'' the issue, such as providing a valid photo ID to the county election officer by the time of the county canvass.', 'https://www.sos.ks.gov/elections/voter-information.html', 'Kansas Secretary of State', '2026-05-14', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('4be72ed940b65d3c', 'KS', '["state","county","municipal"]', 'finance_ethics', 'What is the reporting threshold for itemizing contributions in Kansas?', '["Kansas campaign donation itemization limit","When must I list a donor''s name in KS?","KS GEC small donation rules"]', 'Under K.S.A. 25-4148, campaigns must itemize (list the name and address of) any donor who contributes more than $50 in the aggregate during a reporting period. Contributions of $50 or less may be reported as a lump sum.', 'http://www.ksrevisor.org/statutes/chapters/ch25/025_041_048.html', 'K.S.A. 25-4148', '2026-05-14', 'static', 'statute_citation', 'Treasurers and Donors', 'batch_2026-05-14T17-59-17_kansas_full_v1'),
  ('cd2b13bdb67cbdb1', 'KS', '["state","county","municipal"]', 'finance_ethics', 'Does Kansas provide public financing for campaigns?', '["Kansas public campaign funds","Government funding for candidates KS","KS clean election laws"]', 'No. Kansas does not have a public financing system for any state or local elections. All campaigns are funded through private contributions subject to statutory limits.', 'https://ethics.kansas.gov/', 'Kansas Governmental Ethics Commission', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T17-59-17_kansas_full_v1')
